from flask import Flask, request, jsonify, g
from functools import wraps
import sqlite3
from datetime import datetime
import secrets

app = Flask(__name__)
app.config['DATABASE'] = 'oauth_tokens.db'

def get_db():
    db = getattr(g, '_database', None)
    if db is None:
        db = g._database = sqlite3.connect(app.config['DATABASE'])
        db.row_factory = sqlite3.Row
    return db

@app.teardown_appcontext
def close_connection(exception):
    db = getattr(g, '_database', None)
    if db is not None:
        db.close()

def init_db():
    with app.app_context():
        db = get_db()
        db.execute('''
            CREATE TABLE IF NOT EXISTS access_tokens (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                token TEXT UNIQUE NOT NULL,
                user_id TEXT NOT NULL,
                scope TEXT,
                expires_at TIMESTAMP NOT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                revoked BOOLEAN DEFAULT 0
            )
        ''')
        db.commit()

def validate_token(token):
    db = get_db()
    cursor = db.execute(
        '''
        SELECT * FROM access_tokens 
        WHERE token = ? AND revoked = 0 AND expires_at > ?
        ''',
        (token, datetime.utcnow())
    )
    token_data = cursor.fetchone()
    return dict(token_data) if token_data else None

def require_oauth(scope=None):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            auth_header = request.headers.get('Authorization')
            
            if not auth_header:
                return jsonify({
                    'error': 'missing_token',
                    'error_description': 'Authorization header is missing'
                }), 401
            
            parts = auth_header.split()
            
            if len(parts) != 2 or parts[0].lower() != 'bearer':
                return jsonify({
                    'error': 'invalid_token',
                    'error_description': 'Invalid authorization header format. Expected: Bearer <token>'
                }), 401
            
            token = parts[1]
            token_data = validate_token(token)
            
            if not token_data:
                return jsonify({
                    'error': 'invalid_token',
                    'error_description': 'The access token is invalid, expired, or has been revoked'
                }), 401
            
            if scope:
                token_scopes = token_data.get('scope', '').split() if token_data.get('scope') else []
                required_scopes = scope.split() if isinstance(scope, str) else scope
                
                if not any(s in token_scopes for s in required_scopes):
                    return jsonify({
                        'error': 'insufficient_scope',
                        'error_description': f'The access token does not have the required scope: {scope}'
                    }), 403
            
            g.current_user = token_data['user_id']
            g.token_data = token_data
            
            return f(*args, **kwargs)
        
        return decorated_function
    return decorator

