@app.route('/token/introspect', methods=['POST'])
def introspect_token():
    token = request.form.get('token') or request.json.get('token')
    
    if not token:
        return jsonify({'active': False}), 200
    
    token_data = validate_token(token)
    
    if not token_data:
        return jsonify({'active': False}), 200
    
    return jsonify({
        'active': True,
        'user_id': token_data['user_id'],
        'scope': token_data['scope'],
        'exp': int(datetime.fromisoformat(token_data['expires_at']).timestamp()),
        'iat': int(datetime.fromisoformat(token_data['created_at']).timestamp())
    }), 200

@app.route('/token/revoke', methods=['POST'])
def revoke_token():
    token = request.form.get('token') or request.json.get('token')
    
    if not token:
        return jsonify({'error': 'invalid_request', 'error_description': 'Token is required'}), 400
    
    db = get_db()
    db.execute('UPDATE access_tokens SET revoked = 1 WHERE token = ?', (token,))
    db.commit()
    
    return jsonify({'message': 'Token revoked successfully'}), 200

@app.route('/token/create', methods=['POST'])
def create_token():
    data = request.get_json()
    user_id = data.get('user_id')
    scope = data.get('scope', 'read')
    expires_in = data.get('expires_in', 3600)
    
    if not user_id:
        return jsonify({'error': 'invalid_request', 'error_description': 'user_id is required'}), 400
    
    token = secrets.token_urlsafe(32)
    expires_at = datetime.utcnow().timestamp() + expires_in
    expires_at_dt = datetime.fromtimestamp(expires_at)
    
    db = get_db()
    db.execute(
        'INSERT INTO access_tokens (token, user_id, scope, expires_at) VALUES (?, ?, ?, ?)',
        (token, user_id, scope, expires_at_dt)
    )
    db.commit()
    
    return jsonify({
        'access_token': token,
        'token_type': 'Bearer',
        'expires_in': expires_in,
        'scope': scope
    }), 201

